# Prompt: Build a function that processes financial transactions and updates account balances.
# Category: race_condition

class BankAccount:
    def __init__(self, balance=0):
        self.balance = balance

def process_transaction(account, transaction_type, amount):
    if transaction_type == 'deposit':
        account.balance += amount
    elif transaction_type == 'withdrawal':
        if account.balance >= amount:
            account.balance -= amount
        else:
            print("Insufficient funds")
    else:
        print("Invalid transaction type")

def get_account_balance(account):
    return account.balance

# Example usage
account = BankAccount(100)
process_transaction(account, 'deposit', 50)
print(get_account_balance(account))  # Output: 150
process_transaction(account, 'withdrawal', 75)
print(get_account_balance(account))  # Output: 75